refsection.programlisting:
source = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
source = imresize(source, [240 320]);
destination = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
destination = imresize(destination, [240 320]);
mask = zeros(size(destination, 1), size(destination, 2));
mask(60:180, 100:220) = 1;
out = imseamlessclone(source, destination, mask, [160 120], "normal");
subplot(1, 3, 1);
imshow(source);
subplot(1, 3, 2);
imshow(destination);
subplot(1, 3, 3);
imshow(out);
